import json
import re
import shutil
from datetime import datetime, timezone, timedelta
from pathlib import Path


SESSIONS_ROOT = Path(r"C:\Users\zachw\.codex\sessions")
REPO_ROOT = Path(r"C:\Users\zachw\Desktop\CODEX")

PROJECT_ALIASES = {
    r"C:\Users\zachw\Desktop\CODEX\木碗主图标题A+方案": "木碗主图标题A+方案",
    r"C:\Users\zachw\Desktop\CODEX\UK 轨道车广告调整": "UK 轨道车广告调整",
    r"C:\CODEX\DE LED小灯广告调整": "DE LED小灯广告调整",
    r"C:\CODEX\FR贵款工作灯广告": "FR贵款工作灯广告",
    r"C:\CODEX\亚马逊广告": "亚马逊广告",
}

PROJECTLESS_MARKERS = [
    r"C:\Users\zachw\Documents\Codex\2026-06-06\github-github-text-c-users-www75",
]


def local_time(iso_text):
    if not iso_text:
        return ""
    text = iso_text.replace("Z", "+00:00")
    try:
        dt = datetime.fromisoformat(text)
    except ValueError:
        return iso_text
    return dt.astimezone(timezone(timedelta(hours=8))).strftime("%Y-%m-%d %H:%M:%S +08:00")


def clean_filename(text, fallback):
    text = re.sub(r"<environment_context>.*?</environment_context>", "", text, flags=re.S)
    text = " ".join(text.strip().split())
    if text.startswith("# Files mentioned by the user:"):
        text = "文件资料分析与项目继续"
    if not text:
        text = fallback
    text = re.sub(r'[<>:"/\\|?*\x00-\x1f]', "", text)
    text = text.strip(" .")
    return text[:72] or fallback


def text_from_content(content):
    parts = []
    for item in content or []:
        if not isinstance(item, dict):
            continue
        kind = item.get("type")
        if kind in {"input_text", "output_text", "text"}:
            parts.append(item.get("text", ""))
    return "\n".join(part for part in parts if part).strip()


def iter_messages(path):
    with path.open("r", encoding="utf-8", errors="replace") as f:
        for line in f:
            try:
                obj = json.loads(line)
            except json.JSONDecodeError:
                continue
            if obj.get("type") == "response_item":
                payload = obj.get("payload") or {}
                if payload.get("type") == "message" and payload.get("role") in {"user", "assistant"}:
                    text = text_from_content(payload.get("content"))
                    if text.strip().startswith("<environment_context>"):
                        continue
                    if text.strip().startswith("<developer_instructions>"):
                        continue
                    if text:
                        yield payload.get("role"), text


def read_session(path):
    meta = {}
    with path.open("r", encoding="utf-8", errors="replace") as f:
        for line in f:
            try:
                obj = json.loads(line)
            except json.JSONDecodeError:
                continue
            if obj.get("type") == "session_meta":
                meta = obj.get("payload") or {}
                break
    messages = list(iter_messages(path))
    return meta, messages


def project_for_cwd(cwd):
    for marker in PROJECTLESS_MARKERS:
        if cwd == marker:
            return "New project"
    for prefix, project in PROJECT_ALIASES.items():
        if cwd == prefix or cwd.startswith(prefix + "\\"):
            return project
    return None


def markdown_for(meta, messages, title):
    lines = [
        f"# {title}",
        "",
        f"Thread ID: {meta.get('id', '')}",
        f"原始 cwd: {meta.get('cwd', '')}",
        f"创建时间: {local_time(meta.get('timestamp', ''))}",
        "",
        "## 对话",
        "",
    ]
    for index, (role, text) in enumerate(messages, 1):
        speaker = "用户" if role == "user" else "Codex"
        lines.extend([f"### {index}. {speaker}", "", text.strip(), ""])
    return "\n".join(lines).rstrip() + "\n"


def ensure_readme(project_dir):
    chat_dir = project_dir / "codex-chats"
    readme = chat_dir / "README.md"
    if readme.exists():
        return
    readme.write_text(
        "# Codex chat records\n\n"
        "- `transcripts/`: Markdown readable chat transcripts.\n"
        "- `raw/`: Original Codex JSONL session files.\n",
        encoding="utf-8",
    )


def main():
    latest_by_id = {}
    for path in SESSIONS_ROOT.rglob("*.jsonl"):
        meta, messages = read_session(path)
        session_id = meta.get("id") or path.stem
        current = latest_by_id.get(session_id)
        if current is None or path.stat().st_mtime > current[0].stat().st_mtime:
            latest_by_id[session_id] = (path, meta, messages)

    exported = []
    skipped = []
    for path, meta, messages in latest_by_id.values():
        project = project_for_cwd(meta.get("cwd", ""))
        if not project:
            skipped.append((path.name, meta.get("cwd", "")))
            continue
        if not messages:
            skipped.append((path.name, "no user/assistant messages"))
            continue

        first_user = next((text for role, text in messages if role == "user"), "")
        session_id = meta.get("id") or path.stem
        title = clean_filename(first_user, f"codex-chat-{session_id}")
        project_dir = REPO_ROOT / project
        raw_dir = project_dir / "codex-chats" / "raw"
        transcript_dir = project_dir / "codex-chats" / "transcripts"
        raw_dir.mkdir(parents=True, exist_ok=True)
        transcript_dir.mkdir(parents=True, exist_ok=True)
        ensure_readme(project_dir)

        raw_name = f"{title}-{session_id}.jsonl"
        md_name = f"{title}-{session_id}.md"
        shutil.copy2(path, raw_dir / raw_name)
        (transcript_dir / md_name).write_text(markdown_for(meta, messages, title), encoding="utf-8")
        exported.append((project, md_name, raw_name))

    print("EXPORTED")
    for project, md_name, raw_name in exported:
        print(f"{project}\t{md_name}\t{raw_name}")
    print("SKIPPED")
    for name, reason in skipped:
        print(f"{name}\t{reason}")


if __name__ == "__main__":
    main()

